/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements phone number validation, message formatting, and delivery
 * with retry support. In non-production environments, SMS messages are
 * captured in memory for testing/inspection rather than sent via a
 * real SMS gateway.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
}

export interface SmsConfig {
  /** SMS gateway provider name (e.g. 'twilio', 'vonage'). */
  provider: string;
  /** Sender phone number or short code. */
  fromNumber: string;
  /** Number of retry attempts on transient failures. */
  maxRetries: number;
  /** Base delay in ms between retries (doubled each attempt). */
  retryDelayMs: number;
  /** Maximum message length in characters. */
  maxMessageLength: number;
}

const DEFAULT_SMS_CONFIG: SmsConfig = {
  provider: 'default',
  fromNumber: '+10000000000',
  maxRetries: 3,
  retryDelayMs: 200,
  maxMessageLength: 160,
};

/**
 * Validate that a string looks like an E.164 phone number.
 * Accepts formats like +1234567890 (with country code).
 */
export function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{6,14}$/.test(phone);
}

/**
 * Resolve the phone number from a notification payload.
 * Checks metadata.phone first, then falls back to the recipient field.
 */
export function resolvePhoneNumber(payload: NotificationPayload): string | null {
  if (payload.metadata?.phone && typeof payload.metadata.phone === 'string') {
    const metaPhone = payload.metadata.phone;
    if (isValidPhoneNumber(metaPhone)) {
      return metaPhone;
    }
  }

  if (isValidPhoneNumber(payload.recipient)) {
    return payload.recipient;
  }

  return null;
}

/**
 * Format a notification payload into an SMS-appropriate text message.
 * SMS messages are plain text and must be concise.
 */
export function formatSmsBody(payload: NotificationPayload, maxLength: number): string {
  const message = `${payload.subject}: ${payload.body}`;
  if (message.length <= maxLength) {
    return message;
  }
  return message.substring(0, maxLength - 3) + '...';
}

export class SmsNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private config: SmsConfig;

  /** Optional hook for tests to simulate SMS gateway failures. */
  private smsSendFn: ((sms: SentSms) => Promise<boolean>) | null = null;

  constructor(config?: Partial<SmsConfig>) {
    this.config = { ...DEFAULT_SMS_CONFIG, ...config };
  }

  /**
   * Override the internal SMS send function (for testing).
   * When set, this function is called instead of the default
   * in-memory capture, allowing tests to simulate failures.
   */
  setSmsSendFn(fn: (sms: SentSms) => Promise<boolean>): void {
    this.smsSendFn = fn;
  }

  /**
   * Send an SMS notification.
   * Validates recipient phone number, formats message, and delivers with retry.
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    const phoneNumber = resolvePhoneNumber(payload);
    if (!phoneNumber) {
      this.logger.error(`Invalid or unresolvable phone number: ${payload.recipient}`);
      return false;
    }

    const body = formatSmsBody(payload, this.config.maxMessageLength);

    const sms: SentSms = {
      to: phoneNumber,
      body,
      sentAt: new Date(),
    };

    this.logger.info(`Sending SMS to ${phoneNumber}: ${payload.subject}`);

    const delivered = await this.deliverWithRetry(sms);

    if (delivered) {
      this.sentMessages.push(sms);
      this.logger.info(`SMS delivered to ${phoneNumber}`);
    } else {
      this.logger.error(`SMS delivery failed to ${phoneNumber} after ${this.config.maxRetries} retries`);
    }

    return delivered;
  }

  /**
   * Attempt delivery with exponential-backoff retries.
   */
  private async deliverWithRetry(sms: SentSms): Promise<boolean> {
    let delay = this.config.retryDelayMs;

    for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
      try {
        const success = await this.smsSend(sms);
        if (success) {
          return true;
        }
      } catch (err) {
        this.logger.warn(
          `SMS send attempt ${attempt + 1} failed: ${err instanceof Error ? err.message : String(err)}`,
        );
      }

      if (attempt < this.config.maxRetries) {
        await this.sleep(delay);
        delay *= 2;
      }
    }

    return false;
  }

  /**
   * Internal SMS send. Uses the test hook if set, otherwise
   * captures the message in memory (simulating a successful send).
   */
  private async smsSend(sms: SentSms): Promise<boolean> {
    if (this.smsSendFn) {
      return this.smsSendFn(sms);
    }
    // Default: in-memory capture (for dev/test)
    return true;
  }

  private sleep(ms: number): Promise<void> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return new Promise<void>((resolve) => { (globalThis as any).setTimeout(resolve, ms); });
  }

  /**
   * Get all SMS messages sent through this adapter. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }

  /**
   * Get the current adapter configuration.
   */
  getConfig(): SmsConfig {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsNotificationAdapter,
  isValidPhoneNumber,
  resolvePhoneNumber,
  formatSmsBody,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('SmsNotificationAdapter', () => {
  let adapter: SmsNotificationAdapter;

  beforeEach(() => {
    adapter = new SmsNotificationAdapter();
  });

  describe('send', () => {
    it('should send SMS for a valid phone number recipient', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toContain('Order Confirmation');
    });

    it('should reject invalid phone number recipients', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'not-a-phone',
        subject: 'Test',
        body: 'Test body',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(false);
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should use metadata phone override when recipient is not a phone number', async () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: 'user-123',
        subject: 'Order Update: order-1',
        body: 'Status changed from pending to confirmed.',
        metadata: { phone: '+15559876543' },
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(adapter.getSentMessages()[0]?.to).toBe('+15559876543');
    });

    it('should truncate long messages to maxMessageLength', async () => {
      adapter = new SmsNotificationAdapter({ maxMessageLength: 50 });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'This is a very long message body that should be truncated to fit within SMS limits.',
      };

      await adapter.send(payload);

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body.length).toBeLessThanOrEqual(50);
      expect(sent[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should send all notification types', async () => {
      const types = [
        'order:confirmation',
        'order:status-update',
        'user:welcome',
        'user:profile-updated',
      ] as const;

      for (const type of types) {
        const payload: NotificationPayload = {
          type,
          recipient: '+15551234567',
          subject: `Test ${type}`,
          body: `Body for ${type}`,
        };

        const result = await adapter.send(payload);
        expect(result).toBe(true);
      }

      expect(adapter.getSentMessages()).toHaveLength(4);
    });
  });

  describe('retry behavior', () => {
    it('should retry on transient SMS gateway failure and succeed', async () => {
      adapter = new SmsNotificationAdapter({ maxRetries: 2, retryDelayMs: 1 });

      let attempts = 0;
      adapter.setSmsSendFn(async () => {
        attempts++;
        if (attempts < 2) {
          throw new Error('Gateway timeout');
        }
        return true;
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(attempts).toBe(2);
      expect(adapter.getSentMessages()).toHaveLength(1);
    });

    it('should fail after exhausting all retries', async () => {
      adapter = new SmsNotificationAdapter({ maxRetries: 1, retryDelayMs: 1 });

      adapter.setSmsSendFn(async () => {
        throw new Error('SMS gateway down');
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(false);
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should retry when send returns false', async () => {
      adapter = new SmsNotificationAdapter({ maxRetries: 2, retryDelayMs: 1 });

      let attempts = 0;
      adapter.setSmsSendFn(async () => {
        attempts++;
        return attempts >= 3;
      });

      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
      };

      const result = await adapter.send(payload);

      expect(result).toBe(true);
      expect(attempts).toBe(3);
    });
  });

  describe('configuration', () => {
    it('should use default config', () => {
      const config = adapter.getConfig();
      expect(config.provider).toBe('default');
      expect(config.fromNumber).toBe('+10000000000');
      expect(config.maxRetries).toBe(3);
      expect(config.maxMessageLength).toBe(160);
    });

    it('should accept custom config', () => {
      const custom = new SmsNotificationAdapter({
        provider: 'twilio',
        fromNumber: '+18005551234',
        maxMessageLength: 320,
      });
      const config = custom.getConfig();
      expect(config.provider).toBe('twilio');
      expect(config.fromNumber).toBe('+18005551234');
      expect(config.maxMessageLength).toBe(320);
      expect(config.maxRetries).toBe(3); // still default
    });
  });

  describe('clearSentMessages', () => {
    it('should clear sent message history', async () => {
      await adapter.send({
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Test',
        body: 'Test',
      });

      expect(adapter.getSentMessages()).toHaveLength(1);
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });
});

describe('isValidPhoneNumber', () => {
  it('should accept valid E.164 phone numbers', () => {
    expect(isValidPhoneNumber('+15551234567')).toBe(true);
    expect(isValidPhoneNumber('+442071234567')).toBe(true);
    expect(isValidPhoneNumber('+8613800138000')).toBe(true);
  });

  it('should reject invalid phone numbers', () => {
    expect(isValidPhoneNumber('5551234567')).toBe(false);
    expect(isValidPhoneNumber('+0123456')).toBe(false);
    expect(isValidPhoneNumber('')).toBe(false);
    expect(isValidPhoneNumber('not-a-phone')).toBe(false);
    expect(isValidPhoneNumber('+1')).toBe(false);
    expect(isValidPhoneNumber('+1234')).toBe(false);
  });
});

describe('resolvePhoneNumber', () => {
  it('should return recipient if it is a valid phone number', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: '+15551234567',
      subject: 'Test',
      body: 'Test',
    };
    expect(resolvePhoneNumber(payload)).toBe('+15551234567');
  });

  it('should prefer metadata phone over non-phone recipient', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: 'user-123',
      subject: 'Test',
      body: 'Test',
      metadata: { phone: '+15559876543' },
    };
    expect(resolvePhoneNumber(payload)).toBe('+15559876543');
  });

  it('should return null when no valid phone number can be resolved', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: 'user-123',
      subject: 'Test',
      body: 'Test',
    };
    expect(resolvePhoneNumber(payload)).toBeNull();
  });

  it('should ignore invalid metadata phone and fall back to recipient', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: '+15551234567',
      subject: 'Test',
      body: 'Test',
      metadata: { phone: 'not-valid' },
    };
    expect(resolvePhoneNumber(payload)).toBe('+15551234567');
  });
});

describe('formatSmsBody', () => {
  it('should combine subject and body', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmed',
      body: 'Your order is ready.',
    };
    expect(formatSmsBody(payload, 160)).toBe('Order Confirmed: Your order is ready.');
  });

  it('should truncate messages exceeding max length', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: '+15551234567',
      subject: 'Order Confirmed',
      body: 'A'.repeat(200),
    };
    const result = formatSmsBody(payload, 50);
    expect(result.length).toBe(50);
    expect(result).toMatch(/\.\.\.$/);
  });

  it('should not truncate messages within max length', () => {
    const payload: NotificationPayload = {
      type: 'order:confirmation',
      recipient: '+15551234567',
      subject: 'Hi',
      body: 'Done.',
    };
    const result = formatSmsBody(payload, 160);
    expect(result).toBe('Hi: Done.');
    expect(result).not.toContain('...');
  });
});

